import { useMemo, useState, type ChangeEvent } from "react";

type Status = "operating" | "planned" | "under_construction" | "approved" | "unknown";
type Lifecycle = "raw_import" | "local_working" | "reviewed" | "promoted_public" | "rejected_duplicate" | "retired";
type Precision = "public_dataset" | "city_level" | "county_level" | "state_level" | "unknown";
type Confidence = "high" | "medium" | "low";
type SourceType = "public_dataset" | "permit" | "utility" | "operator" | "news" | "review" | "other";
type QualityBand = "strong" | "moderate" | "weak" | "blocked";
type RegionMode = "state" | "county";
type TaskStatus = "open" | "in_progress" | "blocked" | "done" | "dismissed";
type TaskCategory = "needs_second_source" | "needs_public_url" | "needs_permit_receipt" | "needs_utility_receipt" | "needs_location_review" | "needs_confidence_review" | "needs_warning_resolution" | "needs_source_quality" | "ready_for_promotion" | "manual_follow_up";
type BriefScope = "record" | "region";
type ChecklistStatus = "pass" | "warning" | "fail" | "needs_human";
type ApprovalStatus = "pending" | "approved" | "rejected";
type ReviewerRole = "viewer" | "data_reviewer" | "source_reviewer" | "regional_reviewer" | "publisher" | "admin";
type RolePermission = "view_workspace" | "import_records" | "edit_receipts" | "submit_changes" | "approve_changes" | "reject_changes" | "mark_reviewed" | "promote_records" | "export_public_brief" | "export_regional_packet" | "export_canonical" | "restore_session";
type AuditEventType = "import" | "receipt" | "task" | "brief" | "reviewed" | "promotion" | "session_restore" | "note" | "quality" | "change" | "approval" | "role";

type Receipt = { receiptId?: string; sourceName: string; sourceType: SourceType; sourceUrl?: string; retrievedAt: string; claim: string; confidence: Confidence; batchId?: string };
type LedgerRecord = { id: string; name: string; operator: string; status: Status; state: string; county: string; city?: string; precision: Precision; capacityMW?: number; lifecycle: Lifecycle; confidenceScore: number; reviewWarnings: string[]; receipts: Receipt[]; notes: string[]; importBatchId?: string };
type ImportWarning = { rowNumber: number; level: "info" | "warning" | "blocking"; field?: string; message: string };
type ImportPreview = { batchId: string; createdAt: string; origin: string; rows: Array<{ rowNumber: number; record: LedgerRecord; warnings: ImportWarning[] }>; warnings: ImportWarning[]; digest: string };
type ImportHistoryItem = { batchId: string; committedAt: string; origin: string; rowsCommitted: number; warningCount: number; digest: string };
type ReceiptDraft = { sourceName: string; sourceType: SourceType; sourceUrl: string; retrievedAt: string; claim: string; confidence: Confidence };
type ReceiptEditHistoryItem = { receiptId: string; recordId: string; recordName: string; addedAt: string; sourceName: string; sourceType: SourceType; confidence: Confidence; resolvedWarnings: string[]; remainingWarnings: number; reviewer: string; reviewerRole: ReviewerRole; digest: string };
type SourceQualityReport = { recordId: string; score: number; band: QualityBand; receiptCount: number; sourceTypeCount: number; publicLinkCoverage: number; newestReceiptDaysOld: number | null; highImpactClaimCoverage: "not_applicable" | "needs_second_source" | "covered"; strengths: string[]; gaps: string[]; digest: string };
type RegionalSummary = { id: string; mode: RegionMode; label: string; state: string; county?: string; records: number; canonical: number; needsReview: number; receipts: number; averageQuality: number; qualityBands: Record<QualityBand, number>; reviewGaps: string[]; digest: string };
type ReviewTask = { id: string; recordId: string; regionId?: string; title: string; category: TaskCategory; status: TaskStatus; priority: "low" | "medium" | "high"; detail: string; createdAt: string; source: "generated" | "manual" };
type CanonicalChecklistItem = { id: string; label: string; status: ChecklistStatus; detail: string };
type RoleProfile = { role: ReviewerRole; label: string; description: string; permissions: RolePermission[]; publicBoundary: string[] };
type RoleGateSnapshot = { action: string; permission: RolePermission; allowed: boolean; activeRole: ReviewerRole; reviewer: string; detail: string; digest: string };
type PromotionReceipt = { promotionId: string; recordId: string; recordName: string; promotedAt: string; reviewer: string; reviewerRole: ReviewerRole; reason: string; checklist: CanonicalChecklistItem[]; sourceQuality: SourceQualityReport; publicBriefReady: boolean; safetyAcknowledged: boolean; priorLifecycle: Lifecycle; roleGate: RoleGateSnapshot; digest: string };
type SessionHistoryItem = { sessionId: string; sessionName: string; restoredAt: string; source: string; recordsRestored: number; digest: string };
type AuditTimelineEvent = { id: string; type: AuditEventType; recordId: string; title: string; occurredAt: string; actor?: string; detail: string; status?: string; digest: string };
type PromotionAuditTimeline = { schema: string; generatedAt: string; appVersion: string; recordId: string; recordName: string; events: AuditTimelineEvent[]; summary: { imports: number; receipts: number; tasks: number; briefs: number; promotions: number; changes: number; approvals: number; roles: number; sessionRestores: number; latestEvent: string | null }; digest: string };
type PublicBrief = { schema: string; generatedAt: string; appVersion: string; scope: BriefScope; title: string; summary: string; reviewOnlyNotice: string; boundary: string[]; keyClaims: string[]; sourceReceipts: Array<{ sourceName: string; sourceType: SourceType; sourceUrl?: string; claim: string; confidence: Confidence; retrievedAt: string }>; unresolvedGaps: string[]; quality: SourceQualityReport | { averageQuality: number; qualityBands: Record<QualityBand, number>; regionalRecords: number }; relatedRecords: Array<{ id: string; name: string; state: string; county: string; canonicalBlockers: string[] }>; roleGate: RoleGateSnapshot; digest: string };
type RecordChangeDraft = { name: string; operator: string; status: Status; lifecycle: Lifecycle; state: string; county: string; city: string; precision: Precision; capacityMW: string; confidenceScore: string; reviewWarnings: string };
type ChangeDelta = { field: keyof RecordChangeDraft; before: string; after: string; impact: "low" | "medium" | "high" };
type ChangeReceipt = { changeId: string; approvalId: string; recordId: string; recordName: string; changedAt: string; reviewer: string; reviewerRole: ReviewerRole; reason: string; deltas: ChangeDelta[]; beforeQuality: SourceQualityReport; afterQuality: SourceQualityReport; canonicalBefore: string[]; canonicalAfter: string[]; roleGate: RoleGateSnapshot; digest: string };
type ChangeApprovalRequest = { approvalId: string; recordId: string; recordName: string; requestedAt: string; requestedBy: string; requestedRole: ReviewerRole; reason: string; status: ApprovalStatus; deltas: ChangeDelta[]; recordBefore: LedgerRecord; recordAfter: LedgerRecord; beforeQuality: SourceQualityReport; afterQuality: SourceQualityReport; canonicalBefore: string[]; canonicalAfter: string[]; submitGate: RoleGateSnapshot; decisionReviewer?: string; decisionRole?: ReviewerRole; decisionNote?: string; decisionGate?: RoleGateSnapshot; decidedAt?: string; appliedChangeId?: string; digest: string };
type LocalReviewSession = { schema: string; generatedAt: string; appVersion: string; sessionName: string; activeRole: ReviewerRole; reviewerName: string; roleProfile: RoleProfile; records: LedgerRecord[]; importHistory: ImportHistoryItem[]; receiptHistory: ReceiptEditHistoryItem[]; promotionHistory: PromotionReceipt[]; changeHistory: ChangeReceipt[]; approvalQueue: ChangeApprovalRequest[]; sessionHistory: SessionHistoryItem[]; taskStatusOverrides: Record<string, TaskStatus>; manualTasks: ReviewTask[]; uiState: { selectedId: string; query: string; stateFilter: string; mode: "all" | "canonical" | "review"; regionMode: RegionMode; selectedRegionId: string; briefScope: BriefScope }; digest: string };

