const nowIso = () => new Date().toISOString();
const todayInputDate = () => new Date().toISOString().slice(0, 10);
function digest(payload: unknown) { const text = JSON.stringify(payload); let hash = 2166136261; for (let i = 0; i < text.length; i += 1) { hash ^= text.charCodeAt(i); hash += (hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24); } return `dcl-${(hash >>> 0).toString(16).padStart(8, "0")}`; }
function safeIso(value: string | undefined, fallback = nowIso()) { if (!value) return fallback; const parsed = new Date(value); return parsed.toString() === "Invalid Date" ? fallback : parsed.toISOString(); }
function daysOld(dateText: string) { const parsed = new Date(dateText); if (parsed.toString() === "Invalid Date") return null; return Math.max(0, Math.round((Date.now() - parsed.getTime()) / 86_400_000)); }
function confidenceLabel(score: number): Confidence { if (score >= 80) return "high"; if (score >= 55) return "medium"; return "low"; }
function qualityBand(score: number): QualityBand { if (score >= 80) return "strong"; if (score >= 65) return "moderate"; if (score >= 45) return "weak"; return "blocked"; }
function clampScore(value: string | number) { return Math.max(0, Math.min(100, Number(value) || 0)); }
function parseNumber(value: string) { const parsed = Number(value); return Number.isFinite(parsed) && parsed > 0 ? parsed : undefined; }
function roleCan(role: ReviewerRole, permission: RolePermission) { return roleProfiles[role].permissions.includes(permission); }
function roleGate(action: string, permission: RolePermission, role: ReviewerRole, reviewer: string, detail: string): RoleGateSnapshot { const allowed = roleCan(role, permission); const payload = { action, permission, allowed, role, reviewer, detail }; return { action, permission, allowed, activeRole: role, reviewer, detail, digest: digest(payload) }; }

function scoreRecord(record: LedgerRecord): SourceQualityReport {
  const receiptCount = record.receipts.length;
  const sourceTypeCount = new Set(record.receipts.map((receipt) => receipt.sourceType)).size;
  const publicLinks = record.receipts.filter((receipt) => Boolean(receipt.sourceUrl)).length;
  const publicLinkCoverage = receiptCount ? Math.round((publicLinks / receiptCount) * 100) : 0;
  const receiptAges = record.receipts.map((receipt) => daysOld(receipt.retrievedAt)).filter((age): age is number => age !== null);
  const newestReceiptDaysOld = receiptAges.length ? Math.min(...receiptAges) : null;
  const highImpactClaimCoverage = record.capacityMW && record.capacityMW > 0 ? receiptCount >= 2 && publicLinks >= 1 ? "covered" : "needs_second_source" : "not_applicable";
  let score = 15;
  const strengths: string[] = [];
  const gaps: string[] = [];
  if (receiptCount >= 2) { score += 20; strengths.push("two or more receipts"); } else gaps.push("needs at least two receipts");
  if (sourceTypeCount >= 2) { score += 15; strengths.push("source diversity"); } else gaps.push("needs source diversity");
  if (publicLinkCoverage >= 80) { score += 15; strengths.push("strong public-link coverage"); } else gaps.push("needs stronger public-link coverage");
  if (newestReceiptDaysOld !== null && newestReceiptDaysOld <= 365) { score += 10; strengths.push("recent receipt present"); } else gaps.push("needs recent receipt review");
  if (highImpactClaimCoverage === "covered" || highImpactClaimCoverage === "not_applicable") score += 10; else gaps.push("high-impact MW claim needs second source");
  if (record.confidenceScore >= 70) { score += 10; strengths.push("confidence at or above 70"); } else gaps.push("confidence below 70");
  if (record.reviewWarnings.length === 0) { score += 10; strengths.push("no unresolved review warnings"); } else gaps.push(`${record.reviewWarnings.length} unresolved review warning(s)`);
  if (record.precision === "unknown") { score -= 15; gaps.push("unknown location precision"); }
  const finalScore = Math.max(0, Math.min(100, score));
  return { recordId: record.id, score: finalScore, band: qualityBand(finalScore), receiptCount, sourceTypeCount, publicLinkCoverage, newestReceiptDaysOld, highImpactClaimCoverage, strengths, gaps, digest: digest({ recordId: record.id, finalScore, receiptCount, sourceTypeCount, publicLinkCoverage, newestReceiptDaysOld, highImpactClaimCoverage, gaps }) };
}
function canonicalBlockers(record: LedgerRecord, report = scoreRecord(record)) { const blockers: string[] = []; if (record.lifecycle !== "promoted_public") blockers.push("not promoted_public"); if (record.receipts.length === 0) blockers.push("missing receipt"); if (record.confidenceScore < 70) blockers.push("confidence below 70"); if (record.precision === "unknown") blockers.push("unknown location precision"); if (record.reviewWarnings.length > 0) blockers.push("review warnings remain"); if (report.score < 65) blockers.push("source quality below 65"); return blockers; }
function promotionChecklist(record: LedgerRecord, report: SourceQualityReport, publicBriefReady: boolean, safetyAcknowledged: boolean, reason: string, promotionGate: RoleGateSnapshot): CanonicalChecklistItem[] { return [
  { id: "role", label: "Publisher role selected", status: promotionGate.allowed ? "pass" : "fail", detail: promotionGate.allowed ? `${promotionGate.reviewer} may promote as ${promotionGate.activeRole}.` : `Current role ${promotionGate.activeRole} cannot promote records.` },
  { id: "receipts", label: "Receipts attached", status: record.receipts.length > 0 ? "pass" : "fail", detail: `${record.receipts.length} receipt(s) attached.` },
  { id: "quality", label: "Source quality at or above 65", status: report.score >= 65 ? "pass" : "fail", detail: `Current source quality is ${report.score} (${report.band}).` },
  { id: "confidence", label: "Confidence at or above 70", status: record.confidenceScore >= 70 ? "pass" : "warning", detail: `Current confidence is ${record.confidenceScore}%.` },
  { id: "warnings", label: "No unresolved review warnings", status: record.reviewWarnings.length === 0 ? "pass" : "needs_human", detail: `${record.reviewWarnings.length} unresolved warning(s).` },
  { id: "precision", label: "Location precision is public-safe", status: record.precision !== "unknown" ? "pass" : "fail", detail: `Precision is ${record.precision}.` },
  { id: "brief", label: "Public brief reviewed", status: publicBriefReady ? "pass" : "needs_human", detail: publicBriefReady ? "Reviewer acknowledged public-brief readiness." : "Generate/review a public brief before promotion." },
  { id: "safety", label: "Safety boundary acknowledged", status: safetyAcknowledged ? "pass" : "fail", detail: safetyAcknowledged ? "Reviewer acknowledged public-data boundary." : "Reviewer must acknowledge safety boundary." },
  { id: "reason", label: "Reviewer reason provided", status: reason.trim().length >= 12 ? "pass" : "needs_human", detail: reason.trim().length >= 12 ? "Promotion reason captured." : "Promotion reason is required." }
]; }
function checklistPasses(items: CanonicalChecklistItem[]) { return items.every((item) => item.status === "pass" || item.status === "warning"); }

function splitCsvLine(line: string) { const values: string[] = []; let current = ""; let inQuotes = false; for (let index = 0; index < line.length; index += 1) { const char = line[index]; const next = line[index + 1]; if (char === "\"" && inQuotes && next === "\"") { current += "\""; index += 1; } else if (char === "\"") inQuotes = !inQuotes; else if (char === "," && !inQuotes) { values.push(current.trim()); current = ""; } else current += char; } values.push(current.trim()); return values; }
function parseCsvTable(text: string) { const lines = text.split(/\r?\n/).filter((line) => line.trim().length > 0); if (lines.length === 0) return { headers: [] as string[], rows: [] as { rowNumber: number; row: Record<string, string> }[] }; const headers = splitCsvLine(lines[0]).map((item) => item.trim().toLowerCase()); const rows = lines.slice(1).map((line, index) => { const values = splitCsvLine(line); const row: Record<string, string> = {}; headers.forEach((header, headerIndex) => { row[header] = values[headerIndex]?.trim() || ""; }); return { rowNumber: index + 2, row }; }); return { headers, rows }; }
function readCell(row: Record<string, string>, ...keys: string[]) { for (const key of keys) { const value = row[key]?.trim(); if (value) return value; } return ""; }
function pushWarning(warnings: ImportWarning[], rowNumber: number, level: ImportWarning["level"], message: string, field?: string) { warnings.push({ rowNumber, level, field, message }); }
function normalizeStatus(value: string): Status { const normalized = value.toLowerCase().trim().replace(/\s+/g, "_") as Status; return validStatuses.includes(normalized) ? normalized : "unknown"; }
function normalizeSourceType(value: string): SourceType { const normalized = value.toLowerCase().trim().replace(/\s+/g, "_") as SourceType; return validSourceTypes.includes(normalized) ? normalized : "other"; }
function normalizePrecision(row: Record<string, string>): Precision { const raw = readCell(row, "precision", "location_precision").toLowerCase().trim().replace(/\s+/g, "_") as Precision; if (raw && validPrecisions.includes(raw)) return raw; if (readCell(row, "city")) return "city_level"; if (readCell(row, "county")) return "county_level"; if (readCell(row, "state", "state_abb")) return "state_level"; return "unknown"; }
function buildImportPreview(text: string, origin: string, existingRecords: LedgerRecord[]): ImportPreview { const createdAt = nowIso(); const batchId = digest({ text, origin, createdAt }); const { headers, rows } = parseCsvTable(text); const warnings: ImportWarning[] = []; const existingIds = new Set(existingRecords.map((record) => record.id)); const previewIds = new Set<string>(); if (headers.length === 0) pushWarning(warnings, 1, "blocking", "CSV text is empty or missing a header row."); if (headers.length > 0 && rows.length === 0) pushWarning(warnings, 1, "blocking", "CSV has a header row but no data rows."); const previewRows = rows.map(({ rowNumber, row }) => { const rowWarnings: ImportWarning[] = []; const name = readCell(row, "name") || "Unnamed public record"; const state = readCell(row, "state", "state_abb") || "UNKNOWN"; const id = readCell(row, "id") || digest({ row, rowNumber, batchId }); const sourceUrl = readCell(row, "source_url", "url") || undefined; const confidenceScore = clampScore(readCell(row, "confidence", "confidence_score") || 50); const capacityMW = parseNumber(readCell(row, "capacity_mw", "power_mw", "mw")); if (existingIds.has(id)) pushWarning(rowWarnings, rowNumber, "blocking", `Record id "${id}" already exists in the workspace.`, "id"); if (previewIds.has(id)) pushWarning(rowWarnings, rowNumber, "blocking", `Record id "${id}" appears more than once in this import batch.`, "id"); previewIds.add(id); if (!readCell(row, "state", "state_abb")) pushWarning(rowWarnings, rowNumber, "blocking", "Missing state/state_abb.", "state"); if (!sourceUrl) pushWarning(rowWarnings, rowNumber, "info", "No source_url supplied; reviewers should preserve a public link outside the app.", "source_url"); if (capacityMW && capacityMW > 0) pushWarning(rowWarnings, rowNumber, "warning", "MW capacity is a high-impact claim and should have a second independent source before promotion.", "capacity_mw"); const record: LedgerRecord = { id, name, operator: readCell(row, "operator", "owner") || "Unknown", status: normalizeStatus(readCell(row, "status")), state, county: readCell(row, "county") || "Unknown county", city: readCell(row, "city") || undefined, precision: normalizePrecision(row), capacityMW, lifecycle: "raw_import", confidenceScore, reviewWarnings: ["Imported row needs human review before promotion.", ...rowWarnings.filter((warning) => warning.level !== "info").map((warning) => warning.message)], receipts: [{ sourceName: readCell(row, "source", "source_name") || "CSV import", sourceType: normalizeSourceType(readCell(row, "source_type")), sourceUrl, retrievedAt: safeIso(readCell(row, "retrieved_at", "retrieved") || createdAt), claim: readCell(row, "source_claim", "claim") || `Imported row for ${name}.`, confidence: confidenceLabel(confidenceScore), batchId }], notes: [`Imported through batch ${batchId} from ${origin}.`], importBatchId: batchId }; return { rowNumber, record, warnings: rowWarnings }; }); return { batchId, createdAt, origin, rows: previewRows, warnings, digest: digest({ batchId, previewRows, warnings }) }; }
function allPreviewWarnings(preview: ImportPreview | null) { return preview ? [...preview.warnings, ...preview.rows.flatMap((row) => row.warnings)] : []; }
function makeEmptyReceiptDraft(): ReceiptDraft { return { sourceName: "", sourceType: "public_dataset", sourceUrl: "", retrievedAt: todayInputDate(), claim: "", confidence: "medium" }; }
function isHttpUrl(value: string) { if (!value.trim()) return false; try { const url = new URL(value.trim()); return url.protocol === "http:" || url.protocol === "https:"; } catch { return false; } }
function validateReceiptDraft(draft: ReceiptDraft): ImportWarning[] { const warnings: ImportWarning[] = []; if (!draft.sourceName.trim()) pushWarning(warnings, 0, "blocking", "Source name is required.", "sourceName"); if (!draft.claim.trim()) pushWarning(warnings, 0, "blocking", "Claim text is required so reviewers know exactly what the source supports.", "claim"); if (!draft.retrievedAt.trim() || new Date(draft.retrievedAt).toString() === "Invalid Date") pushWarning(warnings, 0, "blocking", "Retrieved date must be a valid date.", "retrievedAt"); if (!draft.sourceUrl.trim()) pushWarning(warnings, 0, "warning", "No source URL supplied; public links make review and promotion stronger.", "sourceUrl"); if (draft.sourceUrl.trim() && !isHttpUrl(draft.sourceUrl)) pushWarning(warnings, 0, "blocking", "Source URL must start with http:// or https://.", "sourceUrl"); return warnings; }
function buildReceiptFromDraft(draft: ReceiptDraft, record: LedgerRecord, addedAt: string): Receipt { return { receiptId: digest({ recordId: record.id, draft, addedAt }), sourceName: draft.sourceName.trim(), sourceType: draft.sourceType, sourceUrl: draft.sourceUrl.trim() || undefined, retrievedAt: safeIso(draft.retrievedAt, addedAt), claim: draft.claim.trim(), confidence: draft.confidence }; }
function resolveWarningsAfterReceipt(record: LedgerRecord, receipt: Receipt) { const nextReceiptCount = record.receipts.length + 1; const hasPublicLink = Boolean(receipt.sourceUrl); const resolved: string[] = []; const remaining = record.reviewWarnings.filter((warning) => { const lower = warning.toLowerCase(); let shouldResolve = false; if (lower.includes("missing source") && receipt.sourceName) shouldResolve = true; if ((lower.includes("source_url") || lower.includes("source url") || lower.includes("public url")) && hasPublicLink) shouldResolve = true; if ((lower.includes("second public source") || lower.includes("second independent source") || lower.includes("needs a second public source")) && nextReceiptCount >= 2 && hasPublicLink) shouldResolve = true; if (lower.includes("needs permit source") && receipt.sourceType === "permit") shouldResolve = true; if (lower.includes("needs utility source") && receipt.sourceType === "utility") shouldResolve = true; if (lower.includes("imported row needs human review") && receipt.claim.length > 20) shouldResolve = true; if (shouldResolve) { resolved.push(warning); return false; } return true; }); const additions: string[] = []; if (!hasPublicLink) additions.push("Newest receipt has no source URL; attach a public link before promotion."); if (receipt.sourceType === "other") additions.push("Newest receipt source type is other; classify it before promotion if possible."); return { remaining: Array.from(new Set([...remaining, ...additions])), resolved }; }

function buildRegionalSummaries(records: LedgerRecord[], reports: SourceQualityReport[], mode: RegionMode): RegionalSummary[] { const reportMap = new Map(reports.map((report) => [report.recordId, report])); const groups = new Map<string, LedgerRecord[]>(); records.forEach((record) => { const key = mode === "state" ? record.state : `${record.state}::${record.county}`; groups.set(key, [...(groups.get(key) || []), record]); }); return Array.from(groups.entries()).map(([key, groupRecords]) => { const first = groupRecords[0]; const regionReports = groupRecords.map((record) => reportMap.get(record.id) || scoreRecord(record)); const qualityBandCounts: Record<QualityBand, number> = { strong: 0, moderate: 0, weak: 0, blocked: 0 }; regionReports.forEach((report) => { qualityBandCounts[report.band] += 1; }); const reviewGaps = Array.from(new Set([...regionReports.flatMap((report) => report.gaps), ...groupRecords.flatMap((record) => record.reviewWarnings)])).slice(0, 8); const canonical = groupRecords.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length === 0).length; const averageQuality = Math.round(regionReports.reduce((sum, report) => sum + report.score, 0) / Math.max(1, regionReports.length)); const label = mode === "state" ? first.state : `${first.county}, ${first.state}`; return { id: key, mode, label, state: first.state, county: mode === "county" ? first.county : undefined, records: groupRecords.length, canonical, needsReview: groupRecords.length - canonical, receipts: groupRecords.reduce((sum, record) => sum + record.receipts.length, 0), averageQuality, qualityBands: qualityBandCounts, reviewGaps, digest: digest({ key, mode, label, averageQuality, qualityBandCounts, reviewGaps }) }; }).sort((a, b) => b.records - a.records || a.label.localeCompare(b.label)); }
function recordsForRegion(region: RegionalSummary | undefined, records: LedgerRecord[]) { if (!region) return []; return records.filter((record) => region.mode === "state" ? record.state === region.state : record.state === region.state && record.county === region.county); }
function buildRegionalEvidencePacket(region: RegionalSummary, records: LedgerRecord[], reports: SourceQualityReport[], gate: RoleGateSnapshot) { const regionRecords = recordsForRegion(region, records); const reportMap = new Map(reports.map((report) => [report.recordId, report])); const checklist = ["Map-safe summary only", "Review receipt coverage", "Resolve public URL gaps", "Check high-impact MW claims", "Confirm no private coordinates are exported", `Role gate: ${gate.allowed ? "passed" : "blocked"}`]; return { schema: "DataCenterLedger.RegionalEvidencePacket.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, roleGate: gate, region, records: regionRecords, sourceQuality: regionRecords.map((record) => reportMap.get(record.id) || scoreRecord(record)), checklist, digest: digest({ region, regionRecords, checklist, gate }) }; }
function generateReviewTasks(records: LedgerRecord[], reports: SourceQualityReport[], overrides: Record<string, TaskStatus>, manualTasks: ReviewTask[]): ReviewTask[] { const reportMap = new Map(reports.map((report) => [report.recordId, report])); const generated: ReviewTask[] = []; records.forEach((record) => { const report = reportMap.get(record.id) || scoreRecord(record); const base = { recordId: record.id, regionId: `${record.state}::${record.county}`, createdAt: "generated", source: "generated" as const }; const add = (suffix: string, title: string, category: TaskCategory, priority: "low" | "medium" | "high", detail: string) => { const id = `task-${suffix}-${record.id}`; generated.push({ ...base, id, title, category, priority, detail, status: overrides[id] || "open" }); }; record.reviewWarnings.forEach((warning, index) => add(`warning-${index}`, `Resolve warning: ${warning}`, "needs_warning_resolution", "high", warning)); if (report.publicLinkCoverage < 80) add("public-url", "Add public source URL coverage", "needs_public_url", "high", "Attach public links to source receipts where available."); if (report.highImpactClaimCoverage === "needs_second_source") add("second-source", "Find second source for MW claim", "needs_second_source", "high", "MW/capacity claims require stronger corroboration before promotion."); if (report.score < 65) add("quality", "Improve source quality score", "needs_source_quality", "medium", report.gaps.join("; ")); if (record.precision === "unknown") add("location", "Review location precision", "needs_location_review", "medium", "Use state/county/city-level precision only unless exact location is already public."); if (canonicalBlockers(record, report).length === 0) add("promotion", "Ready for promotion review", "ready_for_promotion", "low", "Record currently passes canonical gate."); }); return [...manualTasks, ...generated]; }
function buildRecordBrief(record: LedgerRecord, report: SourceQualityReport, gate: RoleGateSnapshot): PublicBrief { const keyClaims = [`${record.name} is tracked as ${record.status} in ${record.county}, ${record.state}.`, `Current source quality: ${report.score} (${report.band}).`, `Lifecycle: ${record.lifecycle}.`]; const unresolvedGaps = Array.from(new Set([...record.reviewWarnings, ...report.gaps])); const relatedRecords = [{ id: record.id, name: record.name, state: record.state, county: record.county, canonicalBlockers: canonicalBlockers(record, report) }]; const payload = { schema: "DataCenterLedger.PublicBrief.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, scope: "record" as BriefScope, title: `Public review brief: ${record.name}`, summary: `${record.name} is a public-data review record. Review receipts and unresolved gaps before using this brief externally.`, reviewOnlyNotice, boundary: publicBoundary, keyClaims, sourceReceipts: record.receipts, unresolvedGaps, quality: report, relatedRecords, roleGate: gate, digest: "pending" }; return { ...payload, digest: digest(payload) }; }
function buildRegionBrief(region: RegionalSummary, records: LedgerRecord[], reports: SourceQualityReport[], gate: RoleGateSnapshot): PublicBrief { const regionRecords = recordsForRegion(region, records); const reportMap = new Map(reports.map((report) => [report.recordId, report])); const relatedRecords = regionRecords.map((record) => ({ id: record.id, name: record.name, state: record.state, county: record.county, canonicalBlockers: canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)) })); const unresolvedGaps = Array.from(new Set([...region.reviewGaps, ...relatedRecords.flatMap((item) => item.canonicalBlockers)])).slice(0, 12); const payload = { schema: "DataCenterLedger.PublicBrief.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, scope: "region" as BriefScope, title: `Map-safe regional brief: ${region.label}`, summary: `${region.label} contains ${region.records} public review record(s), ${region.canonical} canonical-ready record(s), and ${region.needsReview} needing review.`, reviewOnlyNotice, boundary: publicBoundary, keyClaims: [`Average regional source quality: ${region.averageQuality}.`, `Canonical-ready records: ${region.canonical}/${region.records}.`, "This is a map-safe regional summary, not a facility locator."], sourceReceipts: regionRecords.flatMap((record) => record.receipts).slice(0, 12), unresolvedGaps, quality: { averageQuality: region.averageQuality, qualityBands: region.qualityBands, regionalRecords: region.records }, relatedRecords, roleGate: gate, digest: "pending" }; return { ...payload, digest: digest(payload) }; }
function briefToMarkdown(brief: PublicBrief) { return `# ${brief.title}\n\n${brief.summary}\n\n## Review-only notice\n${brief.reviewOnlyNotice}\n\n## Role gate\n- Action: ${brief.roleGate.action}\n- Role: ${brief.roleGate.activeRole}\n- Allowed: ${brief.roleGate.allowed}\n\n## Public boundary\n${brief.boundary.map((item) => `- ${item}`).join("\n")}\n\n## Key claims\n${brief.keyClaims.map((claim) => `- ${claim}`).join("\n")}\n\n## Source receipts\n${brief.sourceReceipts.map((receipt) => `- ${receipt.sourceName} (${receipt.sourceType}, ${receipt.confidence}) — ${receipt.claim}${receipt.sourceUrl ? ` — ${receipt.sourceUrl}` : ""}`).join("\n")}\n\n## Unresolved gaps\n${brief.unresolvedGaps.length ? brief.unresolvedGaps.map((gap) => `- ${gap}`).join("\n") : "- None captured in the local workspace."}\n\nDigest: ${brief.digest}\n`; }
function makeChangeDraft(record: LedgerRecord): RecordChangeDraft { return { name: record.name, operator: record.operator, status: record.status, lifecycle: record.lifecycle, state: record.state, county: record.county, city: record.city || "", precision: record.precision, capacityMW: record.capacityMW ? String(record.capacityMW) : "", confidenceScore: String(record.confidenceScore), reviewWarnings: record.reviewWarnings.join("\n") }; }
function recordFromChangeDraft(record: LedgerRecord, draft: RecordChangeDraft): LedgerRecord { return { ...record, name: draft.name.trim() || record.name, operator: draft.operator.trim() || "Unknown", status: draft.status, lifecycle: draft.lifecycle, state: draft.state.trim() || record.state, county: draft.county.trim() || record.county, city: draft.city.trim() || undefined, precision: draft.precision, capacityMW: parseNumber(draft.capacityMW), confidenceScore: clampScore(draft.confidenceScore), reviewWarnings: draft.reviewWarnings.split(/\n/).map((item) => item.trim()).filter(Boolean) }; }
function buildChangeDeltas(before: LedgerRecord, draft: RecordChangeDraft): ChangeDelta[] { const beforeDraft = makeChangeDraft(before); return (Object.keys(beforeDraft) as Array<keyof RecordChangeDraft>).flatMap((field) => { const beforeValue = beforeDraft[field].toString(); const afterValue = draft[field].toString(); if (beforeValue === afterValue) return []; const highFields: Array<keyof RecordChangeDraft> = ["state", "county", "city", "precision", "capacityMW", "lifecycle"]; const mediumFields: Array<keyof RecordChangeDraft> = ["status", "confidenceScore", "reviewWarnings"]; const impact: ChangeDelta["impact"] = highFields.includes(field) ? "high" : mediumFields.includes(field) ? "medium" : "low"; return [{ field, before: beforeValue || "—", after: afterValue || "—", impact }]; }); }
function makeChangeReceiptFromApproval(request: ChangeApprovalRequest, reviewer: string, role: ReviewerRole, decisionNote: string, gate: RoleGateSnapshot): ChangeReceipt { const changedAt = nowIso(); const changeId = digest({ approvalId: request.approvalId, changedAt, reviewer, role, decisionNote }); return { changeId, approvalId: request.approvalId, recordId: request.recordId, recordName: request.recordName, changedAt, reviewer: reviewer.trim() || "Approval reviewer", reviewerRole: role, reason: `${request.reason} | Approval note: ${decisionNote.trim() || "Approved without additional note."}`, deltas: request.deltas, beforeQuality: request.beforeQuality, afterQuality: request.afterQuality, canonicalBefore: request.canonicalBefore, canonicalAfter: request.canonicalAfter, roleGate: gate, digest: digest({ changeId, approvalId: request.approvalId, role, gate, deltas: request.deltas, beforeQuality: request.beforeQuality, afterQuality: request.afterQuality }) }; }
function buildPromotionAuditTimeline(record: LedgerRecord, report: SourceQualityReport, importHistory: ImportHistoryItem[], receiptHistory: ReceiptEditHistoryItem[], tasks: ReviewTask[], promotionHistory: PromotionReceipt[], sessionHistory: SessionHistoryItem[], changeHistory: ChangeReceipt[], approvalQueue: ChangeApprovalRequest[], brief: PublicBrief, roleProfile: RoleProfile, reviewerName: string): PromotionAuditTimeline { const events: AuditTimelineEvent[] = []; events.push({ id: digest({ type: "role", record: record.id, roleProfile, reviewerName }), type: "role", recordId: record.id, title: `Active role: ${roleProfile.label}`, occurredAt: nowIso(), actor: reviewerName, detail: roleProfile.description, status: roleProfile.role, digest: digest({ roleProfile, reviewerName }) }); if (record.importBatchId) { const batch = importHistory.find((item) => item.batchId === record.importBatchId); events.push({ id: digest({ type: "import", record: record.id, batch }), type: "import", recordId: record.id, title: "Imported into workspace", occurredAt: batch?.committedAt || nowIso(), detail: `Batch ${record.importBatchId}`, status: batch ? "committed" : "batch reference", digest: digest({ record: record.id, batch }) }); } record.receipts.forEach((receipt, index) => events.push({ id: receipt.receiptId || digest({ receipt, index }), type: "receipt", recordId: record.id, title: `Receipt: ${receipt.sourceName}`, occurredAt: receipt.retrievedAt, detail: receipt.claim, status: receipt.confidence, digest: digest(receipt) })); receiptHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.receiptId, type: "receipt", recordId: record.id, title: `Manual receipt added: ${item.sourceName}`, occurredAt: item.addedAt, actor: `${item.reviewer} (${item.reviewerRole})`, detail: `${item.resolvedWarnings.length} warning(s) resolved.`, status: item.confidence, digest: item.digest })); tasks.filter((task) => task.recordId === record.id).forEach((task) => events.push({ id: task.id, type: "task", recordId: record.id, title: task.title, occurredAt: task.createdAt === "generated" ? nowIso() : task.createdAt, detail: task.detail, status: task.status, digest: digest(task) })); events.push({ id: brief.digest, type: "brief", recordId: record.id, title: "Public brief generated", occurredAt: brief.generatedAt, detail: brief.summary, status: brief.roleGate.allowed ? "role_pass" : "role_blocked", digest: brief.digest }); events.push({ id: report.digest, type: "quality", recordId: record.id, title: "Source quality scored", occurredAt: nowIso(), detail: `${report.score} (${report.band})`, status: report.band, digest: report.digest }); if (record.lifecycle === "reviewed" || record.lifecycle === "promoted_public") events.push({ id: digest({ type: "reviewed", record }), type: "reviewed", recordId: record.id, title: "Record marked reviewed", occurredAt: nowIso(), detail: "Record has passed into reviewed/promoted workflow.", status: record.lifecycle, digest: digest({ record }) }); promotionHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.promotionId, type: "promotion", recordId: record.id, title: "Promoted with receipt", occurredAt: item.promotedAt, actor: `${item.reviewer} (${item.reviewerRole})`, detail: item.reason, status: item.roleGate.allowed ? "promoted_public" : "role_blocked", digest: item.digest })); changeHistory.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.changeId, type: "change", recordId: record.id, title: "Approved change applied", occurredAt: item.changedAt, actor: `${item.reviewer} (${item.reviewerRole})`, detail: `${item.deltas.length} field delta(s). Reason: ${item.reason}`, status: item.canonicalAfter.length ? "review" : "clean", digest: item.digest })); approvalQueue.filter((item) => item.recordId === record.id).forEach((item) => events.push({ id: item.approvalId, type: "approval", recordId: record.id, title: `Change approval ${item.status}`, occurredAt: item.decidedAt || item.requestedAt, actor: item.decisionReviewer ? `${item.decisionReviewer} (${item.decisionRole})` : `${item.requestedBy} (${item.requestedRole})`, detail: `${item.deltas.length} delta(s). ${item.decisionNote || item.reason}`, status: item.status, digest: item.digest })); sessionHistory.forEach((item) => events.push({ id: item.sessionId, type: "session_restore", recordId: record.id, title: "Session restored", occurredAt: item.restoredAt, detail: `${item.recordsRestored} record(s) restored from ${item.source}.`, status: item.sessionName, digest: item.digest })); record.notes.forEach((note, index) => events.push({ id: digest({ record: record.id, note, index }), type: "note", recordId: record.id, title: "Reviewer note", occurredAt: nowIso(), detail: note, digest: digest({ record: record.id, note, index }) })); const sortedEvents = events.sort((a, b) => new Date(b.occurredAt).getTime() - new Date(a.occurredAt).getTime()); const summary = { imports: sortedEvents.filter((e) => e.type === "import").length, receipts: sortedEvents.filter((e) => e.type === "receipt").length, tasks: sortedEvents.filter((e) => e.type === "task").length, briefs: sortedEvents.filter((e) => e.type === "brief").length, promotions: sortedEvents.filter((e) => e.type === "promotion").length, changes: sortedEvents.filter((e) => e.type === "change").length, approvals: sortedEvents.filter((e) => e.type === "approval").length, roles: sortedEvents.filter((e) => e.type === "role").length, sessionRestores: sortedEvents.filter((e) => e.type === "session_restore").length, latestEvent: sortedEvents[0]?.occurredAt || null }; const payload = { schema: "DataCenterLedger.PromotionAuditTimeline.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, recordId: record.id, recordName: record.name, events: sortedEvents, summary, digest: "pending" }; return { ...payload, digest: digest(payload) }; }

function downloadJson(filename: string, payload: unknown) { downloadBlob(filename, new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" })); }
function downloadText(filename: string, text: string) { downloadBlob(filename, new Blob([text], { type: "text/markdown" })); }
function downloadBlob(filename: string, blob: Blob) { const url = URL.createObjectURL(blob); const anchor = document.createElement("a"); anchor.href = url; anchor.download = filename; anchor.click(); URL.revokeObjectURL(url); }
function Stat({ label, value }: { label: string; value: number | string }) { return <div className="stat"><span>{label}</span><strong>{value}</strong></div>; }
function GateBadge({ gate }: { gate: RoleGateSnapshot }) { return <span className={`role-gate ${gate.allowed ? "allowed" : "blocked"}`}>{gate.allowed ? "Role passed" : "Role blocked"}</span>; }

export default function App() {
  const [records, setRecords] = useState<LedgerRecord[]>(starterRecords);
  const [selectedId, setSelectedId] = useState(starterRecords[0].id);
  const [query, setQuery] = useState("");
  const [stateFilter, setStateFilter] = useState("all");
  const [mode, setMode] = useState<"all" | "canonical" | "review">("all");
  const [activeRole, setActiveRole] = useState<ReviewerRole>("data_reviewer");
  const [reviewerName, setReviewerName] = useState("Local reviewer");
  const [importText, setImportText] = useState("");
  const [importPreview, setImportPreview] = useState<ImportPreview | null>(null);
  const [importHistory, setImportHistory] = useState<ImportHistoryItem[]>([]);
  const [receiptDraft, setReceiptDraft] = useState<ReceiptDraft>(() => makeEmptyReceiptDraft());
  const [receiptHistory, setReceiptHistory] = useState<ReceiptEditHistoryItem[]>([]);
  const [regionMode, setRegionMode] = useState<RegionMode>("state");
  const [selectedRegionId, setSelectedRegionId] = useState("");
  const [sessionName, setSessionName] = useState("Local review session");
  const [sessionText, setSessionText] = useState("");
  const [sessionHistory, setSessionHistory] = useState<SessionHistoryItem[]>([]);
  const [taskStatusOverrides, setTaskStatusOverrides] = useState<Record<string, TaskStatus>>({});
  const [manualTasks, setManualTasks] = useState<ReviewTask[]>([]);
  const [manualTaskText, setManualTaskText] = useState("");
  const [briefScope, setBriefScope] = useState<BriefScope>("record");
  const [promotionReason, setPromotionReason] = useState("");
  const [promotionSafetyAck, setPromotionSafetyAck] = useState(false);
  const [promotionBriefAck, setPromotionBriefAck] = useState(false);
  const [promotionHistory, setPromotionHistory] = useState<PromotionReceipt[]>([]);
  const [changeDraft, setChangeDraft] = useState<RecordChangeDraft>(() => makeChangeDraft(starterRecords[0]));
  const [changeReason, setChangeReason] = useState("");
  const [changeHistory, setChangeHistory] = useState<ChangeReceipt[]>([]);
  const [approvalQueue, setApprovalQueue] = useState<ChangeApprovalRequest[]>([]);
  const [approvalDecisionNote, setApprovalDecisionNote] = useState("");

  const roleProfile = roleProfiles[activeRole];
  const selected = records.find((record) => record.id === selectedId) || records[0] || starterRecords[0];
  const reports = useMemo(() => records.map(scoreRecord), [records]);
  const reportMap = useMemo(() => new Map(reports.map((report) => [report.recordId, report])), [reports]);
  const selectedReport = reportMap.get(selected.id) || scoreRecord(selected);
  const states = useMemo(() => Array.from(new Set(records.map((record) => record.state))).sort(), [records]);
  const canonicalRecords = records.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length === 0);
  const reviewRecords = records.filter((record) => canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)).length > 0);
  const regionalSummaries = useMemo(() => buildRegionalSummaries(records, reports, regionMode), [records, reports, regionMode]);
  const selectedRegion = regionalSummaries.find((region) => region.id === selectedRegionId) || regionalSummaries[0];
  const importGate = roleGate("Import records", "import_records", activeRole, reviewerName, "Importing rows changes the local workspace.");
  const receiptGate = roleGate("Add source receipt", "edit_receipts", activeRole, reviewerName, "Adding receipts affects source quality and warning resolution.");
  const submitChangeGate = roleGate("Submit change for approval", "submit_changes", activeRole, reviewerName, "Proposed changes must be queued before workspace mutation.");
  const approvalGate = roleGate("Approve or reject change", "approve_changes", activeRole, reviewerName, "Approvals apply or reject pending local changes.");
  const promotionGate = roleGate("Promote canonical record", "promote_records", activeRole, reviewerName, "Promotion creates a public/canonical local receipt.");
  const publicBriefGate = roleGate("Export public brief", "export_public_brief", activeRole, reviewerName, "Public-facing briefs should be exported by a publisher/admin role.");
  const regionalGate = roleGate("Export regional evidence packet", "export_regional_packet", activeRole, reviewerName, "Regional packets remain map-safe and public-data only.");
  const canonicalExportGate = roleGate("Export canonical registry", "export_canonical", activeRole, reviewerName, "Canonical export is public-facing and role-gated.");
  const restoreGate = roleGate("Restore local review session", "restore_session", activeRole, reviewerName, "Session restore replaces the local workspace state.");
  const importWarnings = allPreviewWarnings(importPreview);
  const hasBlockingImport = importWarnings.some((warning) => warning.level === "blocking");
  const receiptDraftWarnings = validateReceiptDraft(receiptDraft);
  const hasBlockingReceiptDraft = receiptDraftWarnings.some((warning) => warning.level === "blocking");
  const selectedBrief = briefScope === "record" ? buildRecordBrief(selected, selectedReport, publicBriefGate) : selectedRegion ? buildRegionBrief(selectedRegion, records, reports, publicBriefGate) : buildRecordBrief(selected, selectedReport, publicBriefGate);
  const selectedRecordBrief = buildRecordBrief(selected, selectedReport, publicBriefGate);
  const selectedRegionPacket = selectedRegion ? buildRegionalEvidencePacket(selectedRegion, records, reports, regionalGate) : null;
  const tasks = generateReviewTasks(records, reports, taskStatusOverrides, manualTasks);
  const promotionChecklistItems = promotionChecklist(selected, selectedReport, promotionBriefAck, promotionSafetyAck, promotionReason, promotionGate);
  const canPromoteSelected = checklistPasses(promotionChecklistItems);
  const selectedAuditTimeline = buildPromotionAuditTimeline(selected, selectedReport, importHistory, receiptHistory, tasks, promotionHistory, sessionHistory, changeHistory, approvalQueue, selectedRecordBrief, roleProfile, reviewerName);
  const proposedRecord = recordFromChangeDraft(selected, changeDraft);
  const proposedReport = scoreRecord(proposedRecord);
  const changeDeltas = buildChangeDeltas(selected, changeDraft);
  const changeReasonReady = changeReason.trim().length >= 12;
  const pendingApprovals = approvalQueue.filter((item) => item.status === "pending");
  const hasPendingApprovalForSelected = pendingApprovals.some((item) => item.recordId === selected.id);
  const canSubmitApproval = changeDeltas.length > 0 && changeReasonReady && !hasPendingApprovalForSelected && submitChangeGate.allowed;
  const visibleRecords = records.filter((record) => { const haystack = `${record.name} ${record.operator} ${record.county} ${record.city || ""}`.toLowerCase(); const matchesQuery = haystack.includes(query.toLowerCase()); const matchesState = stateFilter === "all" || record.state === stateFilter; const blockers = canonicalBlockers(record, reportMap.get(record.id) || scoreRecord(record)); const matchesMode = mode === "all" || (mode === "canonical" ? blockers.length === 0 : blockers.length > 0); return matchesQuery && matchesState && matchesMode; });

  function selectRecord(recordId: string) { const record = records.find((item) => item.id === recordId); setSelectedId(recordId); if (record) setChangeDraft(makeChangeDraft(record)); }
  function previewImportFromText(origin = "pasted CSV") { setImportPreview(buildImportPreview(importText, origin, records)); }
  function loadSampleImport() { setImportText(sampleCsv); setImportPreview(buildImportPreview(sampleCsv, "sample CSV", records)); }
  async function loadCsvFile(file: File) { const text = await file.text(); setImportText(text); setImportPreview(buildImportPreview(text, file.name, records)); }
  function commitImportPreview() { if (!importPreview || hasBlockingImport || !importGate.allowed) return; const importedRecords = importPreview.rows.map((row) => row.record); setRecords((items) => [...items, ...importedRecords]); setImportHistory((items) => [{ batchId: importPreview.batchId, committedAt: nowIso(), origin: importPreview.origin, rowsCommitted: importedRecords.length, warningCount: importWarnings.length, digest: importPreview.digest }, ...items]); if (importedRecords[0]) selectRecord(importedRecords[0].id); setImportPreview(null); setImportText(""); }
  function addReceiptToSelected() { if (hasBlockingReceiptDraft || !receiptGate.allowed) return; const addedAt = nowIso(); const receipt = buildReceiptFromDraft(receiptDraft, selected, addedAt); const resolution = resolveWarningsAfterReceipt(selected, receipt); const historyItem: ReceiptEditHistoryItem = { receiptId: receipt.receiptId || digest({ receipt, addedAt }), recordId: selected.id, recordName: selected.name, addedAt, sourceName: receipt.sourceName, sourceType: receipt.sourceType, confidence: receipt.confidence, resolvedWarnings: resolution.resolved, remainingWarnings: resolution.remaining.length, reviewer: reviewerName, reviewerRole: activeRole, digest: digest({ receipt, selected: selected.id, addedAt, resolution, reviewerName, activeRole }) }; setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, receipts: [...item.receipts, receipt], reviewWarnings: resolution.remaining, notes: [...item.notes, `Receipt ${historyItem.receiptId} added by ${reviewerName} (${activeRole}).`] } : item)); setReceiptHistory((items) => [historyItem, ...items]); setReceiptDraft(makeEmptyReceiptDraft()); }
  function addManualTask() { if (!manualTaskText.trim()) return; const createdAt = nowIso(); const id = digest({ manualTaskText, selected: selected.id, createdAt }); setManualTasks((items) => [{ id, recordId: selected.id, regionId: `${selected.state}::${selected.county}`, title: manualTaskText.trim(), category: "manual_follow_up", status: "open", priority: "medium", detail: "Manual follow-up task created in local review session.", createdAt, source: "manual" }, ...items]); setManualTaskText(""); }
  function updateTaskStatus(taskId: string, status: TaskStatus) { setTaskStatusOverrides((items) => ({ ...items, [taskId]: status })); }
  function markSelectedReviewed() { const gate = roleGate("Mark record reviewed", "mark_reviewed", activeRole, reviewerName, "Review marker is local and does not prove truth."); if (!gate.allowed) return; setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, lifecycle: "reviewed", notes: [...item.notes, `Marked reviewed by ${reviewerName} (${activeRole}).`] } : item)); }
  function promoteSelected() { if (!canPromoteSelected) return; const promotedAt = nowIso(); const receipt: PromotionReceipt = { promotionId: digest({ record: selected.id, promotedAt, promotionReason, reviewerName, activeRole }), recordId: selected.id, recordName: selected.name, promotedAt, reviewer: reviewerName, reviewerRole: activeRole, reason: promotionReason.trim(), checklist: promotionChecklistItems, sourceQuality: selectedReport, publicBriefReady: promotionBriefAck, safetyAcknowledged: promotionSafetyAck, priorLifecycle: selected.lifecycle, roleGate: promotionGate, digest: digest({ selected, promotionChecklistItems, promotionReason, reviewerName, activeRole, promotionGate }) }; setPromotionHistory((items) => [receipt, ...items]); setRecords((items) => items.map((item) => item.id === selected.id ? { ...item, lifecycle: "promoted_public", notes: [...item.notes, `Promoted with receipt ${receipt.promotionId} by ${reviewerName} (${activeRole}).`] } : item)); }
  function submitChangeForApproval() { if (!canSubmitApproval) return; const requestedAt = nowIso(); const request: ChangeApprovalRequest = { approvalId: digest({ selected: selected.id, requestedAt, changeDeltas, changeReason, reviewerName, activeRole }), recordId: selected.id, recordName: selected.name, requestedAt, requestedBy: reviewerName, requestedRole: activeRole, reason: changeReason.trim(), status: "pending", deltas: changeDeltas, recordBefore: selected, recordAfter: proposedRecord, beforeQuality: selectedReport, afterQuality: proposedReport, canonicalBefore: canonicalBlockers(selected, selectedReport), canonicalAfter: canonicalBlockers(proposedRecord, proposedReport), submitGate: submitChangeGate, digest: digest({ selected, proposedRecord, changeDeltas, changeReason, submitChangeGate }) }; setApprovalQueue((items) => [request, ...items]); setChangeReason(""); }
  function approveChangeRequest(request: ChangeApprovalRequest) { if (!approvalGate.allowed) return; const decidedAt = nowIso(); const decisionGate = approvalGate; const changeReceipt = makeChangeReceiptFromApproval(request, reviewerName, activeRole, approvalDecisionNote, decisionGate); const updatedRequest: ChangeApprovalRequest = { ...request, status: "approved", decisionReviewer: reviewerName, decisionRole: activeRole, decisionNote: approvalDecisionNote.trim() || "Approved.", decisionGate, decidedAt, appliedChangeId: changeReceipt.changeId, digest: digest({ request, decisionGate, decidedAt, changeReceipt }) }; setRecords((items) => items.map((item) => item.id === request.recordId ? { ...request.recordAfter, notes: [...request.recordAfter.notes, `Approved change ${changeReceipt.changeId} applied by ${reviewerName} (${activeRole}).`] } : item)); setApprovalQueue((items) => items.map((item) => item.approvalId === request.approvalId ? updatedRequest : item)); setChangeHistory((items) => [changeReceipt, ...items]); setApprovalDecisionNote(""); if (request.recordId === selected.id) setChangeDraft(makeChangeDraft(request.recordAfter)); }
  function rejectChangeRequest(request: ChangeApprovalRequest) { const rejectGate = roleGate("Reject change", "reject_changes", activeRole, reviewerName, "Rejection records a decision but does not mutate the record."); if (!rejectGate.allowed) return; const decidedAt = nowIso(); const updatedRequest: ChangeApprovalRequest = { ...request, status: "rejected", decisionReviewer: reviewerName, decisionRole: activeRole, decisionNote: approvalDecisionNote.trim() || "Rejected without additional note.", decisionGate: rejectGate, decidedAt, digest: digest({ request, rejectGate, decidedAt, decisionNote: approvalDecisionNote }) }; setApprovalQueue((items) => items.map((item) => item.approvalId === request.approvalId ? updatedRequest : item)); setApprovalDecisionNote(""); }
  function buildSession(): LocalReviewSession { const payload: LocalReviewSession = { schema: "DataCenterLedger.LocalReviewSession.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, sessionName, activeRole, reviewerName, roleProfile, records, importHistory, receiptHistory, promotionHistory, changeHistory, approvalQueue, sessionHistory, taskStatusOverrides, manualTasks, uiState: { selectedId, query, stateFilter, mode, regionMode, selectedRegionId: selectedRegion?.id || "", briefScope }, digest: "pending" }; return { ...payload, digest: digest(payload) }; }
  function exportSession() { downloadJson(`dcl-session-v2.4-${Date.now()}.json`, buildSession()); }
  function restoreSessionObject(session: Partial<LocalReviewSession>, source: string) { if (!restoreGate.allowed) return; if (!Array.isArray(session.records)) throw new Error("Session is missing records array."); setRecords(session.records); setImportHistory(session.importHistory || []); setReceiptHistory(session.receiptHistory || []); setPromotionHistory(session.promotionHistory || []); setChangeHistory(session.changeHistory || []); setApprovalQueue(session.approvalQueue || []); setSessionHistory((items) => [{ sessionId: digest({ source, restoredAt: nowIso(), session }), sessionName: session.sessionName || "Restored session", restoredAt: nowIso(), source, recordsRestored: session.records?.length || 0, digest: session.digest || digest(session) }, ...(session.sessionHistory || items)]); setTaskStatusOverrides(session.taskStatusOverrides || {}); setManualTasks(session.manualTasks || []); if (session.activeRole && roleProfiles[session.activeRole]) setActiveRole(session.activeRole); if (session.reviewerName) setReviewerName(session.reviewerName); if (session.uiState?.selectedId) setSelectedId(session.uiState.selectedId); }
  function restorePastedSession() { try { restoreSessionObject(JSON.parse(sessionText), "pasted JSON"); setSessionText(""); } catch (error) { alert(error instanceof Error ? error.message : "Could not restore session."); } }
  async function restoreSessionFile(file: File) { try { restoreSessionObject(JSON.parse(await file.text()), file.name); } catch (error) { alert(error instanceof Error ? error.message : "Could not restore session file."); } }
  function exportLedger() { downloadJson("datacenter-ledger-v2.4.json", { schema: "DataCenterLedger.Workspace.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, roleProfile, reviewerName, roleGates: { canonicalExportGate, publicBriefGate, regionalGate }, records, sourceQuality: reports, regionalSummaries, importHistory, receiptHistory, promotionHistory, changeHistory, approvalQueue, tasks, sessionHistory, digest: digest({ records, reports, regionalSummaries, approvalQueue, roleProfile }) }); }
  function exportCanonical() { if (!canonicalExportGate.allowed) return; downloadJson("datacenter-ledger-canonical-v2.4.json", { schema: "DataCenterLedger.CanonicalRegistry.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, roleGate: canonicalExportGate, records: canonicalRecords, sourceQuality: canonicalRecords.map((record) => reportMap.get(record.id) || scoreRecord(record)), promotionHistory, changeHistory, digest: digest({ canonicalRecords, promotionHistory, changeHistory, canonicalExportGate }) }); }
  function exportApprovalQueue() { downloadJson("datacenter-ledger-change-approval-queue-v2.4.json", { schema: "DataCenterLedger.ChangeApprovalQueue.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, roleProfile, approvalQueue, digest: digest({ approvalQueue, roleProfile }) }); }
  function exportRoleProfile() { downloadJson("datacenter-ledger-role-profile-v2.4.json", { schema: "DataCenterLedger.RoleProfile.v2.4", generatedAt: nowIso(), appVersion: APP_VERSION, reviewerName, activeRole, roleProfile, gates: { importGate, receiptGate, submitChangeGate, approvalGate, promotionGate, publicBriefGate, regionalGate, canonicalExportGate, restoreGate }, boundary: publicBoundary, digest: digest({ reviewerName, activeRole, roleProfile }) }); }

  const field = (key: keyof RecordChangeDraft, label: string, kind: "text" | "number" = "text") => <label>{label}<input type={kind} value={changeDraft[key]} onChange={(event) => setChangeDraft({ ...changeDraft, [key]: event.target.value })} /></label>;

  return <main className="shell">
    <section className="hero"><p className="eyebrow">DataCenterLedger Explorer · v{APP_VERSION}</p><h1>Public-data review cockpit for data center records</h1><p>{reviewOnlyNotice}</p><div className="stats"><Stat label="Records" value={records.length} /><Stat label="Canonical" value={canonicalRecords.length} /><Stat label="Needs review" value={reviewRecords.length} /><Stat label="Pending approvals" value={pendingApprovals.length} /><Stat label="Role" value={roleProfile.label} /></div></section>

    <section className="panel role-panel"><div className="panelHeader"><div><p className="eyebrow">v2.4 Approval Role Profiles</p><h2>Local reviewer role</h2><p>{roleProfile.description}</p></div><button onClick={exportRoleProfile}>Export role packet</button></div><div className="role-grid"><label>Reviewer name<input value={reviewerName} onChange={(event) => setReviewerName(event.target.value)} /></label><label>Active role<select value={activeRole} onChange={(event) => setActiveRole(event.target.value as ReviewerRole)}>{Object.values(roleProfiles).map((profile) => <option key={profile.role} value={profile.role}>{profile.label}</option>)}</select></label></div><div className="permission-grid">{roleProfile.permissions.map((permission) => <span key={permission} className="permission-chip">{permission}</span>)}</div><div className="gate-grid">{[importGate, receiptGate, submitChangeGate, approvalGate, promotionGate, publicBriefGate, regionalGate, canonicalExportGate, restoreGate].map((gate) => <div key={gate.action} className={`gate-card ${gate.allowed ? "allowed" : "blocked"}`}><strong>{gate.action}</strong><span>{gate.permission}</span><GateBadge gate={gate} /></div>)}</div><p className="boundary-note">Role profiles are a local governance aid, not authentication. They do not prove source truth and do not make private data safe to publish.</p></section>

    <section className="toolbar"><input placeholder="Search name/operator/county" value={query} onChange={(event) => setQuery(event.target.value)} /><select value={stateFilter} onChange={(event) => setStateFilter(event.target.value)}><option value="all">All states</option>{states.map((state) => <option key={state}>{state}</option>)}</select><select value={mode} onChange={(event) => setMode(event.target.value as typeof mode)}><option value="all">All records</option><option value="canonical">Canonical-ready</option><option value="review">Needs review</option></select><button onClick={exportLedger}>Export ledger</button><button disabled={!canonicalExportGate.allowed} onClick={exportCanonical}>Export canonical</button></section>

    <section className="grid two"><div className="panel"><div className="panelHeader"><div><p className="eyebrow">Records</p><h2>Review queue</h2></div></div>{visibleRecords.map((record) => { const report = reportMap.get(record.id) || scoreRecord(record); const blockers = canonicalBlockers(record, report); return <button key={record.id} className={`recordRow ${selected.id === record.id ? "selected" : ""}`} onClick={() => selectRecord(record.id)}><strong>{record.name}</strong><span>{record.county}, {record.state} · {record.lifecycle}</span><span>Quality {report.score} · {blockers.length ? `${blockers.length} blocker(s)` : "canonical-ready"}</span></button>; })}</div><div className="panel"><p className="eyebrow">Source quality</p><h2>{selected.name}</h2><div className="quality-score"><strong>{selectedReport.score}</strong><span>{selectedReport.band}</span></div><p>{selected.county}, {selected.state} · {selected.precision}</p><ul>{selectedReport.gaps.slice(0, 6).map((gap) => <li key={gap}>{gap}</li>)}</ul></div></section>

    <section className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.2 Import Workbench</p><h2>CSV import review</h2></div><GateBadge gate={importGate} /></div><textarea value={importText} onChange={(event) => setImportText(event.target.value)} placeholder="Paste normalized public CSV rows here" /><div className="buttonRow"><button onClick={() => previewImportFromText()}>Preview import</button><button onClick={loadSampleImport}>Load sample</button><label className="fileButton">Load CSV file<input type="file" accept=".csv,text/csv" onChange={(event: ChangeEvent<HTMLInputElement>) => event.target.files?.[0] && loadCsvFile(event.target.files[0])} /></label><button disabled={!importPreview || hasBlockingImport || !importGate.allowed} onClick={commitImportPreview}>Commit import</button></div>{importPreview && <div className="mini-list"><strong>{importPreview.rows.length} row(s), {importWarnings.length} warning(s)</strong>{importWarnings.slice(0, 6).map((warning, index) => <span key={index}>{warning.level}: {warning.message}</span>)}</div>}</section>

    <section className="grid two"><div className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.5 Map-Safe Regional View</p><h2>Regional summaries</h2></div><select value={regionMode} onChange={(event) => setRegionMode(event.target.value as RegionMode)}><option value="state">State</option><option value="county">County</option></select></div><p className="boundary-note">Regional view is not a facility locator and does not aggregate private coordinates.</p>{regionalSummaries.map((region) => <button key={region.id} className={`recordRow ${selectedRegion?.id === region.id ? "selected" : ""}`} onClick={() => setSelectedRegionId(region.id)}><strong>{region.label}</strong><span>{region.records} record(s) · avg quality {region.averageQuality}</span><span>{region.canonical} canonical · {region.needsReview} needs review</span></button>)}<button disabled={!selectedRegionPacket || !regionalGate.allowed} onClick={() => selectedRegionPacket && downloadJson("regional-evidence-packet-v2.4.json", selectedRegionPacket)}>Export regional evidence packet</button></div><div className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.8 Task Board</p><h2>Selected record tasks</h2></div></div><div className="buttonRow"><input value={manualTaskText} onChange={(event) => setManualTaskText(event.target.value)} placeholder="Manual follow-up task" /><button onClick={addManualTask}>Add task</button></div>{tasks.filter((task) => task.recordId === selected.id).slice(0, 8).map((task) => <div key={task.id} className="task-card"><strong>{task.title}</strong><p>{task.detail}</p><select value={task.status} onChange={(event) => updateTaskStatus(task.id, event.target.value as TaskStatus)}><option value="open">open</option><option value="in_progress">in progress</option><option value="blocked">blocked</option><option value="done">done</option><option value="dismissed">dismissed</option></select></div>)}</div></section>

    <section className="grid two"><div className="panel"><div className="panelHeader"><div><p className="eyebrow">v1.3 Receipt Editor</p><h2>Add source receipt</h2></div><GateBadge gate={receiptGate} /></div><div className="form-grid"><input placeholder="Source name" value={receiptDraft.sourceName} onChange={(event) => setReceiptDraft({ ...receiptDraft, sourceName: event.target.value })} /><select value={receiptDraft.sourceType} onChange={(event) => setReceiptDraft({ ...receiptDraft, sourceType: event.target.value as SourceType })}>{validSourceTypes.map((type) => <option key={type}>{type}</option>)}</select><input placeholder="Public source URL" value={receiptDraft.sourceUrl} onChange={(event) => setReceiptDraft({ ...receiptDraft, sourceUrl: event.target.value })} /><input type="date" value={receiptDraft.retrievedAt} onChange={(event) => setReceiptDraft({ ...receiptDraft, retrievedAt: event.target.value })} /><select value={receiptDraft.confidence} onChange={(event) => setReceiptDraft({ ...receiptDraft, confidence: event.target.value as Confidence })}><option value="high">high</option><option value="medium">medium</option><option value="low">low</option></select></div><textarea placeholder="Exactly what does the source support?" value={receiptDraft.claim} onChange={(event) => setReceiptDraft({ ...receiptDraft, claim: event.target.value })} /><button disabled={hasBlockingReceiptDraft || !receiptGate.allowed} onClick={addReceiptToSelected}>Add receipt</button>{receiptDraftWarnings.map((warning, index) => <p key={index} className="warning">{warning.level}: {warning.message}</p>)}</div><div className="panel"><p className="eyebrow">Receipts</p><h2>{selected.receipts.length} attached</h2>{selected.receipts.map((receipt, index) => <div key={receipt.receiptId || index} className="mini-card"><strong>{receipt.sourceName}</strong><span>{receipt.sourceType} · {receipt.confidence}</span><p>{receipt.claim}</p>{receipt.sourceUrl && <a href={receipt.sourceUrl} target="_blank" rel="noreferrer">Open public source</a>}</div>)}</div></section>

    <section className="panel public-brief-panel"><div className="panelHeader"><div><p className="eyebrow">v1.9 Public Brief Generator</p><h2>{selectedBrief.title}</h2></div><GateBadge gate={publicBriefGate} /></div><select value={briefScope} onChange={(event) => setBriefScope(event.target.value as BriefScope)}><option value="record">Selected record</option><option value="region">Selected region</option></select><p>{selectedBrief.summary}</p><ul>{selectedBrief.keyClaims.map((claim) => <li key={claim}>{claim}</li>)}</ul><div className="buttonRow"><button disabled={!publicBriefGate.allowed} onClick={() => downloadJson("public-brief-v2.4.json", selectedBrief)}>Export brief JSON</button><button disabled={!publicBriefGate.allowed} onClick={() => downloadText("public-brief-v2.4.md", briefToMarkdown(selectedBrief))}>Export brief Markdown</button></div></section>

    <section className="panel canonical-cockpit"><div className="panelHeader"><div><p className="eyebrow">v2.0 Canonical Review Mode</p><h2>Promotion cockpit</h2></div><GateBadge gate={promotionGate} /></div><div className="form-grid"><label>Promotion reason<textarea value={promotionReason} onChange={(event) => setPromotionReason(event.target.value)} /></label><label><input type="checkbox" checked={promotionBriefAck} onChange={(event) => setPromotionBriefAck(event.target.checked)} /> Public brief reviewed</label><label><input type="checkbox" checked={promotionSafetyAck} onChange={(event) => setPromotionSafetyAck(event.target.checked)} /> Safety boundary acknowledged</label></div><div className="checklist-grid">{promotionChecklistItems.map((item) => <div key={item.id} className={`check-card ${item.status}`}><strong>{item.label}</strong><span>{item.status}</span><p>{item.detail}</p></div>)}</div><div className="buttonRow"><button disabled={!roleCan(activeRole, "mark_reviewed")} onClick={markSelectedReviewed}>Mark reviewed</button><button disabled={!canPromoteSelected} onClick={promoteSelected}>Promote with receipt</button></div></section>

    <section className="panel change-review-panel"><div className="panelHeader"><div><p className="eyebrow">v2.3 Change Approval Queue + v2.4 Roles</p><h2>Propose, queue, approve, or reject changes</h2></div><GateBadge gate={submitChangeGate} /></div><div className="form-grid change-fields">{field("name", "Name")}{field("operator", "Operator")}<label>Status<select value={changeDraft.status} onChange={(event) => setChangeDraft({ ...changeDraft, status: event.target.value as Status })}>{validStatuses.map((status) => <option key={status}>{status}</option>)}</select></label><label>Lifecycle<select value={changeDraft.lifecycle} onChange={(event) => setChangeDraft({ ...changeDraft, lifecycle: event.target.value as Lifecycle })}>{["raw_import", "local_working", "reviewed", "promoted_public", "rejected_duplicate", "retired"].map((status) => <option key={status}>{status}</option>)}</select></label>{field("state", "State")}{field("county", "County")}{field("city", "City")}<label>Precision<select value={changeDraft.precision} onChange={(event) => setChangeDraft({ ...changeDraft, precision: event.target.value as Precision })}>{validPrecisions.map((precision) => <option key={precision}>{precision}</option>)}</select></label>{field("capacityMW", "Capacity MW", "number")}{field("confidenceScore", "Confidence", "number")}<label>Review warnings<textarea value={changeDraft.reviewWarnings} onChange={(event) => setChangeDraft({ ...changeDraft, reviewWarnings: event.target.value })} /></label></div><textarea placeholder="Reviewer reason for proposed change" value={changeReason} onChange={(event) => setChangeReason(event.target.value)} /><div className="diff-table"><div><strong>Field</strong><strong>Before</strong><strong>After</strong><strong>Impact</strong></div>{changeDeltas.length ? changeDeltas.map((delta) => <div key={delta.field}><span>{delta.field}</span><span>{delta.before}</span><span>{delta.after}</span><span>{delta.impact}</span></div>) : <p>No field changes drafted.</p>}</div><div className="quality-delta"><span>Before quality {selectedReport.score}</span><span>After quality {proposedReport.score}</span><span>{hasPendingApprovalForSelected ? "Pending approval exists for this record" : "No pending approval for selected record"}</span></div><button disabled={!canSubmitApproval} onClick={submitChangeForApproval}>Submit change for approval</button></section>

    <section className="panel approval-queue-panel"><div className="panelHeader"><div><p className="eyebrow">Approval queue</p><h2>{approvalQueue.length} request(s)</h2></div><div className="buttonRow"><GateBadge gate={approvalGate} /><button onClick={exportApprovalQueue}>Export approval queue</button></div></div><textarea placeholder="Decision note for approve/reject" value={approvalDecisionNote} onChange={(event) => setApprovalDecisionNote(event.target.value)} />{approvalQueue.map((request) => <div key={request.approvalId} className={`approval-card ${request.status}`}><div><strong>{request.recordName}</strong><span>{request.status} · requested by {request.requestedBy} ({request.requestedRole})</span><p>{request.reason}</p></div><div>{request.deltas.map((delta) => <span key={delta.field} className="impact-chip">{delta.field}: {delta.impact}</span>)}</div>{request.status === "pending" && <div className="buttonRow"><button disabled={!approvalGate.allowed} onClick={() => approveChangeRequest(request)}>Approve + apply</button><button disabled={!roleCan(activeRole, "reject_changes")} onClick={() => rejectChangeRequest(request)}>Reject</button></div>}{request.decisionReviewer && <p>Decision: {request.decisionReviewer} ({request.decisionRole}) — {request.decisionNote}</p>}</div>)}</section>

    <section className="panel audit-panel"><div className="panelHeader"><div><p className="eyebrow">v2.1 Promotion Audit Timeline</p><h2>Selected record audit trail</h2></div><button onClick={() => downloadJson("promotion-audit-timeline-v2.4.json", selectedAuditTimeline)}>Export timeline</button></div><div className="stats"><Stat label="Events" value={selectedAuditTimeline.events.length} /><Stat label="Approvals" value={selectedAuditTimeline.summary.approvals} /><Stat label="Changes" value={selectedAuditTimeline.summary.changes} /><Stat label="Roles" value={selectedAuditTimeline.summary.roles} /></div>{selectedAuditTimeline.events.slice(0, 10).map((event) => <div key={event.id} className="timeline-event"><strong>{event.title}</strong><span>{event.type} · {event.status || "recorded"}</span><p>{event.detail}</p></div>)}</section>

    <section className="panel session-panel"><div className="panelHeader"><div><p className="eyebrow">v1.7 Local Review Session</p><h2>Save / load local workspace</h2></div><GateBadge gate={restoreGate} /></div><input value={sessionName} onChange={(event) => setSessionName(event.target.value)} /><div className="buttonRow"><button onClick={exportSession}>Export session</button><label className="fileButton">Load session file<input type="file" accept="application/json,.json" onChange={(event: ChangeEvent<HTMLInputElement>) => event.target.files?.[0] && restoreSessionFile(event.target.files[0])} /></label></div><textarea placeholder="Paste session JSON" value={sessionText} onChange={(event) => setSessionText(event.target.value)} /><button disabled={!restoreGate.allowed} onClick={restorePastedSession}>Restore pasted session</button></section>
  </main>;
}
